"use client";

import { useState, useCallback } from "react";
// import TitleBar from "../components/TitleBar";
// import ActivityBar from "../components/ActivityBar";
// import LeftSidebar from "../components/LeftSidebar";
// import EditorPanel from "../components/EditorPanel";
// import ChatPanel from "../components/ChatPanel";
// import StatusBar from "../components/StatusBar";

export default function Home() {
  const [openFiles, setOpenFiles] = useState<string[]>([]);
  const [activeFile, setActiveFile] = useState<string | null>(null);

  const handleOpenFile = useCallback((file: string) => {
    setOpenFiles((prev) => {
      if (!prev.includes(file)) {
        return [...prev, file];
      }
      return prev;
    });
    setActiveFile(file);
  }, []);

  const handleCloseFile = useCallback((file: string) => {
    setOpenFiles((prev) => {
      const newFiles = prev.filter((f) => f !== file);
      return newFiles;
    });
    setActiveFile((prev) => {
      if (prev === file) {
        const remaining = openFiles.filter((f) => f !== file);
        return remaining.length > 0 ? remaining[remaining.length - 1] : null;
      }
      return prev;
    });
  }, [openFiles]);

  const handleSelectTab = useCallback((file: string) => {
    setActiveFile(file);
  }, []);

  return (
    <div className="flex flex-col h-screen w-screen overflow-hidden bg-[#0d0d0d]">
      {/* Title Bar */}
      {/* <TitleBar /> */}

      {/* Main Content Area */}
      <div className="flex flex-1 overflow-hidden">
        {/* Activity Bar */}
        {/* <ActivityBar /> */}

        {/* Explorer Sidebar */}
        {/* <LeftSidebar onOpenFile={handleOpenFile} activeFile={activeFile} /> */}

        {/* Editor Panel */}
          {/* <EditorPanel
          openFiles={openFiles}
          activeFile={activeFile}
          onSelectTab={handleSelectTab}
          onCloseTab={handleCloseFile}
        /> */}

        {/* Chat Panel */}
        {/* <ChatPanel /> */}
      </div>

      {/* Status Bar */}
      {/* <StatusBar activeFile={activeFile} /> */}
    </div>
  );
}
